const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');
const app = express();
app.use(express.json());
app.get('/health', (_req, res) => res.json({ ok: true }));
app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);
module.exports = app;

// src/lib/errors.js
const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

// src/modules/members/routes.js
const express = require('express');
const router = express.Router();
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'User ID and role are required');
  }
  try {
    const member = await membersService.createMember(userId, role);
    res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create member');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');

let membersStore = [];

const createMember = async (userId, role) => {
  const member = { id: randomUUID(), userId, role };
  membersStore.push(member);
  return member;
};

module.exports = { createMember };

// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { description } = req.body;
  if (!description) {
    return sendError(res, 400, 'INVALID_INPUT', 'Description is required');
  }
  try {
    const task = await tasksService.createTask(description);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create task');
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    let tasks = await tasksService.getAllTasks();
    if (status === 'todo' || status === 'done') {
      tasks = tasks.filter(task => task.status === 'done');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to get tasks');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTask(taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    if (error.code === 'NOT_FOUND') {
      return sendError(res, 404, 'NOT_FOUND', 'Task not found');
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to update task');
  }
});

module.exports = router;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');

let tasksStore = [];

const createTask = async (description) => {
  const task = { id: randomUUID(), description, status: 'todo' };
  tasksStore.push(task);
  return task;
};

const getAllTasks = async () => {
  return tasksStore;
};

const updateTask = async (taskId, status) => {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    throw { code: 'NOT_FOUND' };
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
};

module.exports = { createTask, getAllTasks, updateTask };

